/**
 * Interactive text meetings for "SiteCommand Training" sandboxes.
 *
 * A scheduled task can carry a meeting: the Day panel hyperlinks the task text,
 * and clicking it opens /training/meeting?project=…&meeting=… in a new tab. The
 * meeting is a text conversation — the fake attendees (GC precon team personas)
 * talk in turn, and whenever it's the PM's (the trainee's) turn to weigh in, the
 * page prompts them to respond via text. The attendees' turns are generated by
 * Gemini (see app/api/projects/[id]/training/meetings/[meetingId]), grounded in
 * the agenda and facts defined here. The meeting sticks to the agenda; if the
 * trainee asks something off-script, the attendees answer the aside in character
 * and then steer back to the current agenda item.
 *
 * This module is pure, client-safe content (types + the meeting definitions +
 * lookup helpers) so both the Day panel and the API route can import it. Only
 * the Day-1 PM bid-review meeting is defined today; add future meetings to
 * TRAINING_MEETINGS.
 */

import type { SimRole } from "@/lib/simulation-constants";
import type { SkillKey } from "@/lib/training-skills";
import { TRAINING_SUBS } from "@/lib/training-emails";
import { HC_MEETINGS, HEALTHCARE_TYPE } from "@/lib/training-healthcare";

export type MeetingSpeaker = {
  /** Stable key used in transcripts ("okafor"). "user" is reserved for the PM. */
  key: string;
  name: string;
  title: string;
  /** How this persona talks — grounding for the LLM, not shown in the UI. */
  style: string;
};

export type MeetingAgendaItem = {
  title: string;
  /** Grounding facts / talking points the attendees work from on this item. */
  points: string[];
};

export type MeetingTurn = {
  /** A speaker key from the meeting's speakers, or "user" for the PM. */
  speaker: string;
  text: string;
};

/**
 * A hidden "test" planted in the meeting. The attendees surface the clue
 * naturally (per `plant`) but never resolve it themselves — the checkpoint is
 * whether the PM catches it (flags it, asks about it, turns it into a
 * decision/action). Scored when the meeting adjourns; results land in the
 * saved minutes and the phase Job Review.
 */
export type MeetingCheckpoint = {
  id: string;
  /** Short label shown in the score card. */
  title: string;
  /** What catching it looks like — shown in the minutes and used for scoring. */
  expectation: string;
  /**
   * LLM-only instruction for how the attendees drop the clue in conversation
   * (never shown to the trainee, never dumped into fallback dialogue).
   */
  plant: string;
  /** Agenda item (0-based) where the clue belongs. */
  plantAgendaIndex: number;
  /**
   * Natural sentence appended to the canned fallback turn for that agenda item
   * so the clue still surfaces when Gemini is unavailable. Omit when the clue
   * is already carried by the agenda points / bid tab.
   */
  fallbackLine?: string;
  /**
   * Degraded scoring heuristic when Gemini is unavailable: the checkpoint
   * counts as caught if any PM turn contains any of these (case-insensitive).
   */
  keywords: string[];
};

/**
 * A timed question posed during a meeting's site walk. The trainee has
 * `timeLimitSeconds` (meeting-level) to answer on the spot:
 *   - FULL credit — a confident, substantively correct answer.
 *   - HALF credit — they don't have the fact but correctly tell the asker
 *     where the information lives (spec section, submittal log, fixture
 *     schedule, testing reports, …).
 *   - NO credit — the timer expires, or the answer is vague/wrong.
 * Asked deterministically by the client (no LLM between questions) so the
 * countdown is reliable; graded server-side when the minutes are generated.
 */
export type WalkQuestion = {
  id: string;
  /** Speaker key of the persona asking (must be one of the meeting speakers). */
  speakerKey: string;
  /** Short label shown in the score card. */
  title: string;
  /** The full turn text — scene-setting + the question itself. */
  ask: string;
  /** What a full-credit answer contains (drives the judge and the score card). */
  fullAnswer: string;
  /** Where the info lives — correctly naming this earns half credit. */
  sourceHint: string;
  /** Skill this question evidences in the competency profile. */
  skill: SkillKey;
  /** Degraded grading: any of these in the answer → full credit. */
  fullKeywords: string[];
  /** Degraded grading: any of these in the answer → half credit. */
  sourceKeywords: string[];
};

export type MeetingWalk = {
  /** Deterministic transition turn that starts the walk after the sit-down agenda. */
  intro: MeetingTurn;
  /** Seconds the trainee has to answer each question (the "on the spot" window). */
  timeLimitSeconds: number;
  questions: WalkQuestion[];
  /** Deterministic closing turn after the last question — then the meeting adjourns. */
  outro: MeetingTurn;
};

export type TrainingMeeting = {
  id: string;
  role: SimRole;
  /** In-sim day the meeting's task lands on. */
  day: number;
  /** Exact TrainingTask.task string this meeting hyperlinks in the Day panel. */
  taskMatch: string;
  title: string;
  objective: string;
  deliverable: string;
  /** Attendees other than the PM. The first entry runs the meeting. */
  speakers: MeetingSpeaker[];
  agenda: MeetingAgendaItem[];
  /** Hidden tests scored against the transcript when the meeting adjourns. */
  checkpoints: MeetingCheckpoint[];
  /**
   * Deterministic opening turns (served without an LLM call) that run the
   * meeting up to the first point where the PM is expected to respond.
   */
  opening: MeetingTurn[];
  /**
   * Reference facts the attendees (and the minute-taker/scorer) work from —
   * e.g. the bid tab, or the project status snapshot for an OAC. Plain text.
   */
  facts?: string;
  /** Optional timed site-walk Q&A that runs after the sit-down agenda. */
  walk?: MeetingWalk;
};

