/** Roster sub's seeded bid for a trade (keeps meeting numbers consistent with
 *  the buyout email threads). */
function rosterBid(trade: string): number {
  return TRAINING_SUBS.find((s) => s.trade === trade)?.bid ?? 0;
}

function money(value: number): string {
  return `$${Math.round(value).toLocaleString("en-US")}`;
}

/**
 * The bid tab the precon team walks through. One entry per trade: the estimate
 * line, each bidder (the seeded roster firm is flagged), and any flags the team
 * should raise. Competitor firms are fictional; the roster firm's number comes
 * from TRAINING_SUBS so the meeting agrees with the seeded buyout emails.
 */
type BidLine = { firm: string; amount: number | null; roster?: boolean; note?: string };
type BidTabTrade = { trade: string; estimate: number; bids: BidLine[]; flag?: string };

